import type { Defect, BoundingBox, ImageMetadata, InspectionCriteria } from '../src';

function makeDefect(
  id: string,
  severity: 'critical' | 'major' | 'minor' | 'cosmetic',
  confidence: number,
  category: 'crack' | 'scratch' | 'dent' | 'corrosion' | 'contamination' |
             'dimensional' | 'surface' | 'assembly' | 'other' = 'crack',
  description = 'test defect',
  boundingBox?: BoundingBox,
): Defect {
  return { id, category, severity, confidence, description, boundingBox };
}

function makeImage(width = 1920, height = 1080): ImageMetadata {
  return { id: 'img-1', width, height, format: 'jpeg', sizeBytes: 204800 };
}

function makeCriteria(
  mode: 'defect-detection' | 'dimensional' | 'surface-quality' | 'assembly-check' = 'defect-detection',
  opts: { maxDefects?: number; allowedSeverities?: ('critical'|'major'|'minor'|'cosmetic')[]; minScore?: number } = {}
): InspectionCriteria {
  return { mode, ...opts };
}

