  it(`total items across all groups equals input length`, () => { const d=[makeDefect('a','critical',1),makeDefect('b','major',1),makeDefect('c','minor',1)]; const r=groupDefectsBySeverity(d); const total=r.critical.length+r.major.length+r.minor.length+r.cosmetic.length; expect(total).toBe(3); });
